/* Atlas entry navigation — renders the "related phenomena" strip and prev/next
 * links on each entry page, data-driven from window.ATLAS_ENTRIES (generated by
 * tools/build.mjs into site/entries.js). No fetch, so it works from file://.
 *
 * Each entry page includes:
 *   <body data-slug="game-of-life">
 *   ... <nav class="related" data-atlas-nav></nav> ...
 *   <script src="../../entries.js"></script>
 *   <script src="../../lib/nav.js"></script>
 * and this script fills the <nav> with related links + prev/next, so the
 * cross-navigation stays in sync with the manifest automatically. */
(function () {
  'use strict';

  // Give every entry page the shared favicon without editing 11 static files.
  if (!document.querySelector('link[rel="icon"]')) {
    const fav = document.createElement('link');
    fav.rel = 'icon'; fav.type = 'image/svg+xml'; fav.href = '../../favicon.svg';
    document.head.appendChild(fav);
  }

  linkGlossaryTerms();

  const entries = window.ATLAS_ENTRIES;
  const mount = document.querySelector('[data-atlas-nav]');
  if (!entries || !mount) return;

  const slug = document.body.dataset.slug;
  const i = entries.findIndex(e => e.slug === slug);
  if (i < 0) return;
  const here = entries[i];
  const by = (s) => entries.find(e => e.slug === s);
  const link = (s) => `../${s}/index.html`;

  const parts = [];

  // Related phenomena (from the manifest's `related`, filtered to published).
  const related = (here.related || []).map(by).filter(Boolean);
  if (related.length) {
    parts.push('<h2>Related phenomena</h2>');
    parts.push('<div class="rel-links">' +
      related.map(e =>
        `<a href="${link(e.slug)}" title="${escapeAttr(e.blurb)}">${escapeHtml(e.title)} &rarr;</a>`
      ).join('') + '</div>');
  }

  // Prev / next across the whole Atlas (manifest order), wrapping around.
  const prev = entries[(i - 1 + entries.length) % entries.length];
  const next = entries[(i + 1) % entries.length];
  parts.push('<div class="prevnext">' +
    `<a class="prev" href="${link(prev.slug)}" title="Previous (← key)">&larr; <span>${escapeHtml(prev.title)}</span></a>` +
    `<a class="home" href="../../index.html" title="The map">the map</a>` +
    `<a class="next" href="${link(next.slug)}" title="Next (→ key)"><span>${escapeHtml(next.title)}</span> &rarr;</a>` +
    '</div>');
  parts.push('<p class="navhint">flip with the <kbd>&larr;</kbd> <kbd>&rarr;</kbd> keys · <kbd>R</kbd> for a random phenomenon</p>');

  mount.innerHTML = parts.join('\n');

  // Keyboard navigation — browse the Atlas like a book. Ignored while a control
  // (slider/select) is focused, so arrow keys still tune simulations.
  document.addEventListener('keydown', (e) => {
    if (e.altKey || e.ctrlKey || e.metaKey) return;
    const t = document.activeElement;
    if (t && /^(INPUT|SELECT|TEXTAREA|BUTTON)$/.test(t.tagName)) return;
    if (e.key === 'ArrowLeft') { location.href = link(prev.slug); }
    else if (e.key === 'ArrowRight') { location.href = link(next.slug); }
    else if (e.key === 'r' || e.key === 'R') {
      const others = entries.filter(x => x.slug !== slug);
      if (others.length) location.href = link(others[Math.floor(Math.random() * others.length)].slug);
    }
  });

  function escapeHtml(s) {
    return String(s).replace(/[&<>]/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[c]));
  }
  function escapeAttr(s) {
    return String(s).replace(/[&<>"]/g, c =>
      ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]));
  }

  // Auto-link defined terms in the prose to the glossary (the reverse of the
  // glossary's own links). The FIRST plain-text occurrence of each curated term
  // becomes a subtle "definition" link to glossary.html#<anchor>. Longer phrases
  // are matched first; text inside existing links, headings, and code is skipped;
  // each term is linked at most once per page.
  function linkGlossaryTerms() {
    const prose = document.querySelector('.prose');
    if (!prose || !document.createTreeWalker) return;
    const TERMS = [
      ['self-organized criticality', 'self-organized-criticality'],
      ['computational irreducibility', 'computational-irreducibility'],
      ['percolation threshold', 'percolation-threshold'],
      ['associative memory', 'associative-memory'],
      ['bounded confidence', 'bounded-confidence'],
      ['complex contagion', 'complex-contagion'],
      ['positive feedback', 'positive-feedback'],
      ['symmetry breaking', 'symmetry-breaking'],
      ['chimera state', 'chimera-state'],
      ['cyclic dominance', 'cyclic-dominance'],
      ['order parameter', 'order-parameter'],
      ['phase transition', 'phase-transition'],
      ['excitable medium', 'excitable-medium'],
      ['excitable media', 'excitable-medium'],
      ['edge of chaos', 'edge-of-chaos'],
      ['limit cycle', 'limit-cycle'],
      ['power law', 'power-law'],
      ['power-law', 'power-law'],
      ['scale-free', 'scale-free'],
      ['universality', 'universality'],
      ['stigmergy', 'stigmergy'],
      ['refractory', 'refractory-period'],
      ['coarsening', 'coarsening'],
      ['attractor', 'attractor'],
      ['criticality', 'criticality'],
    ].sort((a, b) => b[0].length - a[0].length);
    const SKIP = { A: 1, H1: 1, H2: 1, H3: 1, CODE: 1, DT: 1 };
    const done = {};
    const esc = (s) => s.replace(/[-/\\^$*+?.()|[\]{}]/g, '\\$&');
    for (const [term, anchor] of TERMS) {
      if (done[anchor]) continue;
      const re = new RegExp('\\b' + esc(term) + '\\b', 'i');
      const walker = document.createTreeWalker(prose, NodeFilter.SHOW_TEXT);
      let node;
      while ((node = walker.nextNode())) {
        let p = node.parentNode, skip = false;
        while (p && p !== prose) { if (SKIP[p.tagName]) { skip = true; break; } p = p.parentNode; }
        if (skip) continue;
        const m = re.exec(node.nodeValue);
        if (!m) continue;
        const a = document.createElement('a');
        a.href = '../../glossary.html#' + anchor;
        a.className = 'g-term';
        a.title = 'definition →';
        a.textContent = node.nodeValue.slice(m.index, m.index + m[0].length);
        const frag = document.createDocumentFragment();
        const before = node.nodeValue.slice(0, m.index);
        const after = node.nodeValue.slice(m.index + m[0].length);
        if (before) frag.appendChild(document.createTextNode(before));
        frag.appendChild(a);
        if (after) frag.appendChild(document.createTextNode(after));
        node.parentNode.replaceChild(frag, node);
        done[anchor] = 1;
        break;
      }
    }
  }
})();
